interface TakePhotoParams {  // defaults:
    camera?:any;  //CameraID;      // CameraID.RIGHT
    photoType?:any;  //PhotoType;  // PhotoType.SNAP
    undistort?:boolean;    // true
}

interface TakePhotoResponse {
    id:string;
    url:string;
}

interface StorePhotoParams {
    id?:string;
    buffer?:Buffer;
}

interface StorePhotoResponse {
    id:string;
    url:string;
    thumbnails:ThumbnailsResponse;
}

interface ThumbnailsResponse {
    [name:string]:string;  // uuid for each thumbnail
}

interface Thumbnails {
    [name:string]:[number, number];
}

// export enum ThumbnailType {
//     thumb       = <any>'thumb',       // mobile
//     thumb_robot = <any>'thumb_robot'  // robot
// };

interface ViewfinderParams {
    enabled?:boolean;  // Turn preview viewport on or off
    camera?:any;  //CameraID;  // One of 0, 1; signifying camera id
    width?:number;     // viewfinder width in pixels
    height?:number;    // viewfinder height in pixels
    x?:number;         // top edge of viewfinder location in pixels
    y?:number;         // right edge of viewfinder location in pixels
}

interface ViewfinderResponse extends ViewfinderParams {
    ts: [number, number];
}

type ErrCallback = (err?:Error) => void;
type TakePhotoCallback = (err:Error, response?:TakePhotoResponse) => void;
type StorePhotoCallback = (err:Error, response?:StorePhotoResponse) => void;
type ViewfinderCallback = (err:Error, response?:ViewfinderResponse) => void;


export class Media {
    public CameraID:any; //: typeof CameraID;
    public PhotoType:any; //: typeof PhotoType;
    public ThumbnailType:any; //: typeof ThumbnailType;
    public mediaService:any;
    public mediaManagerService:any;
    private proxyUrl:string;
    private isInitialized:boolean ;

    public takePhoto(callback:TakePhotoCallback);
    public takePhoto():Promise<TakePhotoResponse>;
    public takePhoto(params:TakePhotoParams, callback:TakePhotoCallback);
    public takePhoto(params:TakePhotoParams):Promise<TakePhotoResponse>;

    public storePhoto(id:string, callback:StorePhotoCallback);
    public storePhoto(id:string):Promise<StorePhotoResponse>;
    public storePhoto(id:string, params:StorePhotoParams, callback:StorePhotoCallback);
    public storePhoto(id:string, params:StorePhotoParams):Promise<StorePhotoResponse>;
    public storePhoto(buffer:Buffer, callback:StorePhotoCallback);
    public storePhoto(buffer:Buffer):Promise<StorePhotoResponse>;
    public storePhoto(buffer:Buffer, params:StorePhotoParams, callback:StorePhotoCallback);
    public storePhoto(buffer:Buffer, params:StorePhotoParams):Promise<StorePhotoResponse>;
    public storePhoto(params:StorePhotoParams, callback:StorePhotoCallback);
    public storePhoto(params:StorePhotoParams):Promise<StorePhotoResponse>;

    public deletePhoto(id:string, callback:ErrCallback);
    public deletePhoto(id:string):Promise<void>;
    
    public getPhoto(id:string, callback:(err:Error, image?:PIXI.Texture) => void);
    public getPhoto(id:string):Promise<PIXI.Texture>;

    public getUrl(contentId:string):string;
    public getPreviewUrl(id:string):string;

    public setViewfinder(enabled:true|false, callback:ErrCallback);
    public setViewfinder(enabled:true|false):Promise<void>;
    public setViewfinder(enabled:true, params:ViewfinderParams, callback:ErrCallback);
    public setViewfinder(enabled:true, params:ViewfinderParams):Promise<void>;
    public setViewfinder(params:ViewfinderParams, callback:ErrCallback);
    public setViewfinder(params:ViewfinderParams):Promise<void>;

    public getViewfinder(callback:ViewfinderCallback);
    public getViewfinder():Promise<ViewfinderResponse>;
}

export default Media;
